sql:
SELECT group_name
FROM point_groups
WHERE group_order < (SELECT MAX(group_order) FROM point_groups);

SELECT matrix_id, operation_id
FROM symmetry_operation_matrices
WHERE matrix_elements = '[[1, 0], [0, 1]]';

SELECT pg.group_name, pg.group_description, ir.representation_name, ir.representation_dimension
FROM point_groups pg
INNER JOIN irreducible_representations ir ON pg.group_id = ir.group_id;

external_knowledge:
- Representations are like blueprints for how abstract concepts (groups) can be expressed in simpler, more understandable forms (matrices).;
- The dimension of a representation is akin to the size of this blueprint.;
- Matrix elements are the key points on this blueprint, with their descriptions offering insight into their roles, and their values representing their specific numerical significance.;
- A celestial map metaphorically represents the systematic and complex nature of these representations and their elements.

sql:
SELECT computation_result
FROM computations
WHERE computation_id = 1 AND project_id = 1;

SELECT irreducible_representations.representation_name, irreducible_representations.representation_dimension, point_groups.group_name
FROM irreducible_representations
JOIN point_groups ON irreducible_representations.group_id = point_groups.group_id;

SELECT group_order, group_description 
FROM space_groups 
WHERE group_name = 'P4/nmm';

SELECT COS(element_value) 
FROM matrix_elements 
WHERE representation_id = 1;

SELECT operation_name
FROM symmetry_operations
WHERE operation_type = 'rotational';

SELECT operation_name, operation_type
FROM symmetry_operations
WHERE operation_id > 5;

SELECT operation_id, operation_name, operation_matrix
FROM symmetry_operations
WHERE operation_matrix IS NOT NULL AND operation_matrix = '1111';

SELECT DISTINCT researchers.researcher_name, researchers.researcher_description
FROM researchers
INNER JOIN collaborations ON researchers.researcher_id = collaborations.researcher_id;

SELECT researcher_name, email 
FROM researchers 
WHERE researcher_id NOT IN (SELECT researcher_id FROM research_projects);

SELECT AVG(representation_dimension) 
FROM irreducible_representations 
WHERE group_id = 0;
